mapper.select:
SELECT u.user_id, u.realname, u.img, u.dept_id, d.dept_name, u.post, u.mobile, u.email, COALESCE(NULLIF(u.employee_status, ''), CASE WHEN u.status = 1 THEN 'active' WHEN u.status = 2 THEN 'resigned' ELSE 'disabled' END) AS employee_status, ( SELECT MAX(COALESCE(t.completed_time, t.due_date, t.update_time, t.create_time)) FROM crm_task t WHERE t.assigned_to = u.user_id ) AS recent_task_time FROM manager_user u LEFT JOIN manager_dept d ON u.dept_id = d.dept_id WHERE 1 = 1
AND ( u.realname LIKE CONCAT('%', #{query.keyword}, '%') OR u.username LIKE CONCAT('%', #{query.keyword}, '%') OR u.mobile LIKE CONCAT('%', #{query.keyword}, '%') OR u.email LIKE CONCAT('%', #{query.keyword}, '%') OR u.post LIKE CONCAT('%', #{query.keyword}, '%') OR d.dept_name LIKE CONCAT('%', #{query.keyword}, '%') )
AND u.dept_id IN
#{deptId}
AND COALESCE(NULLIF(u.employee_status, ''), CASE WHEN u.status = 1 THEN 'active' WHEN u.status = 2 THEN 'resigned' ELSE 'disabled' END) = #{query.employeeStatus}
ORDER BY CASE COALESCE(NULLIF(u.employee_status, ''), CASE WHEN u.status = 1 THEN 'active' WHEN u.status = 2 THEN 'resigned' ELSE 'disabled' END) WHEN 'active' THEN 0 WHEN 'disabled' THEN 1 WHEN 'resigned' THEN 2 ELSE 3 END, u.create_time DESC
